insert into public.species_subtitles (locale, slug, descriptor, subtitle_story)
values
    ('en', 'aardvark', 'The night-digging bug vacuum animal', 'The Aardvark is a nighttime mammal with a long nose and tongue made for slurping ants and termites. It digs fast, hides underground, and comes out when the world gets cooler and quieter.'),
    ('en', 'aardwolf', 'The termite-eating ghost hyena animal', 'The Aardwolf looks like a small hyena, but instead of chasing big food it licks up termites by the thousands. It wins by choosing a different meal and a quieter path.'),
    ('en', 'addax', 'The pale dune survivor animal', 'The Addax is a desert antelope built for places that seem almost too dry for life. It survives by saving energy, moving carefully, and matching the color of the sand itself.'),
    ('en', 'adelie-penguin', 'The ice-edge commuter animal', 'The Adelie Penguin lives where ice, sea, and stone all meet. It is a little traveler of one of the hardest places on Earth, marching between colony and ocean again and again.'),
    ('en', 'african-bullfrog', 'The giant puddle frog animal', 'The African Bullfrog waits out dry times underground and explodes into action when rain fills temporary pools. It turns short wet windows into a whole life plan.'),
    ('en', 'african-civet', 'The striped night prowler animal', 'The African Civet wanders at night with a striped coat that feels half shadow and half warning. It finds food in many ways, showing that flexibility is its real strength.'),
    ('en', 'african-grey-parrot', 'The talking forest thinker animal', 'The African Grey Parrot is famous for copying words and sounds, but its real power is how well it learns. It carries a sharp mind inside a feathered forest body.'),
    ('en', 'african-wild-dog', 'The fast pack signal hunter animal', 'The African Wild Dog is a fast hunter with big ears and a coat covered in splashy colors. It works with its pack like a team, so everyone helps chase, turn, and catch.'),
    ('en', 'aldabra-giant-tortoise', 'The island elder shell animal', 'The Aldabra Giant Tortoise moves slowly enough to make time itself feel different. Its giant shell and long life make it seem like a walking piece of island history.'),
    ('en', 'alligator-snapping-turtle', 'The riverbed trap-mouth animal', 'The Alligator Snapping Turtle waits so still on the bottom that it almost looks like a rock. Then it wiggles a tiny lure in its mouth and lets dinner come closer all by itself.'),
    ('en', 'alpaca', 'The soft cloud pasture animal', 'The Alpaca is a gentle woolly animal that stays close to its herd and lives well in cool mountain air. It feels soft on the outside, but it is built to handle high, windy places.'),
    ('en', 'alpine-ibex', 'The horned cliff walker animal', 'The Alpine Ibex makes steep mountain faces look almost easy. It shows how a body built for grip and balance can turn danger into ordinary ground.'),
    ('en', 'american-alligator', 'The swamp-edge patience force animal', 'The American Alligator is a heavy reptile that waits in warm swamps and rivers with patient eyes. At the edge of the water, waiting is one of its strongest tricks.'),
    ('en', 'american-bison', 'The thunder-prairie force animal', 'The Bison is a giant grassland animal with a huge front end that pushes through weather and distance. When a herd moves together, the ground almost seems to feel it.'),
    ('en', 'american-bullfrog', 'The booming pond-claim king animal', 'The American Bullfrog is a large pond frog with a deep booming call. Its loud voice helps it claim space and tell other frogs, ''This pond is mine.'''),
    ('en', 'andean-condor', 'The mountain sky giant animal', 'The Andean Condor rides mountain air with wings so wide it hardly seems real. It cleans the land from above and makes cliffs feel like launchpads into another scale of sky.'),
    ('en', 'arapaima', 'The giant river armor animal', 'The Arapaima is one of the world''s biggest freshwater fish, rising to the surface for air with a heavy splash. It turns tropical rivers into a place for giants.'),
    ('en', 'arctic-tern', 'The endless summer traveler animal', 'The Arctic Tern lives on a route so long it chases summer from one end of the Earth to the other. Tiny wings can still carry one of the biggest journeys in nature.'),
    ('en', 'argentine-black-and-white-tegu', 'The checkerboard ground dragon animal', 'The Tegu is a big lizard that can dig, roam, bask, and eat all kinds of things. It feels like a flexible desert-and-forest machine made to handle change.'),
    ('en', 'atlantic-puffin', 'The master of three realms animal', 'The Atlantic Puffin is a funny seabird with a bright beak and wings that work in air and underwater. It can fly in the sky, walk on land, and paddle through the sea like it belongs in all three places.'),
    ('en', 'atlas-moth', 'The giant final-message animal', 'The Atlas Moth is a giant moth with huge wings and a short adult life. It spends most of its time preparing for one brief beautiful moment to fly, mate, and pass life on.'),
    ('en', 'axolotl', 'The smiling regeneration mystery animal', 'The Axolotl is a smiling water animal with feathery gills sticking out from its head. It is amazing because it can grow back lost body parts, almost like a little healing magician.'),
    ('en', 'aye-aye', 'The spooky wood-tapper animal', 'The Aye-aye is a strange tree-dwelling primate that taps wood, listens for grubs, and pulls them out with a skinny finger. It sounds odd, but every odd part is part of the plan.'),
    ('en', 'babirusa', 'The strange-tusk island rooter animal', 'The Babirusa is a wild pig from islands in Indonesia, famous for its strange curling tusks. It may look odd, but it helps stir and feed the forest in quiet ways.'),
    ('en', 'bald-eagle', 'The high water-reading ruler animal', 'The Bald Eagle is a giant bird with a white head and sharp eyes that can spot food from far away. It teaches that seeing the whole picture first can make the next move easier.'),
    ('en', 'bali-myna', 'The rare white song jewel animal', 'The Bali Myna is a rare white bird with a soft crest and bright blue skin around its eyes. It reminds us that beautiful living things need protection when there are only a few left.'),
    ('en', 'barn-owl', 'The silent dark-listening hunter animal', 'The Barn Owl is a pale night bird with a heart-shaped face that helps it hear tiny sounds in the dark. It flies so quietly that mice often do not know it is coming.'),
    ('en', 'barn-swallow', 'The swift barn-sky sweeper animal', 'The Barn Swallow is a quick little bird that zips through the sky catching insects while it flies. It turns the air above fields and farms into its moving dinner table.'),
    ('en', 'basilisk-lizard', 'The water-running lizard animal', 'The Basilisk can dash across water for a moment, making it seem almost magical. Really, it is using long toes, fast feet, and perfect timing.'),
    ('en', 'bearded-dragon', 'The sun-basking dragon animal', 'The Bearded Dragon likes to warm itself in the sun and puff up when it wants to look bigger. It uses heat, posture, and timing to handle a hard dry world.'),
    ('en', 'beluga-whale', 'The white sea singer animal', 'The Beluga is a white Arctic whale that talks with many clicks, whistles, and squeaks. Its soft shape and flexible neck help it move through icy water with surprising grace.'),
    ('en', 'binturong', 'The shaggy canopy seed carrier animal', 'The Binturong is a shaggy tree animal with a tail that can help it hold onto branches. As it eats fruit and travels, it helps spread seeds so new forest can grow.'),
    ('en', 'black-and-white-colobus', 'The cape-tailed canopy animal', 'The Colobus monkey wears a flowing black-and-white coat that seems made for moving through high leaves. Its long tail turns leaps into smooth controlled swings.'),
    ('en', 'black-mamba', 'The lightning-fast warning serpent animal', 'The Black Mamba is a very fast snake with quick movement and a strong warning display. It likes clear direct action and does not waste time when danger comes close.'),
    ('en', 'black-necked-stilt', 'The pink-legged marsh animal', 'The Black-necked Stilt looks as if someone stretched a small bird up on pink stilts. Those long legs let it walk through shallow water where shorter birds cannot reach as easily.'),
    ('en', 'black-rhinoceros', 'The armored thorn-path animal', 'The Black Rhinoceros is a huge plant-eater with a pointed lip for grabbing branches and leaves. It moves through rough bush like a living bulldozer with a nose made for browsing.'),
    ('en', 'black-swan', 'The midnight water glider animal', 'The Black Swan glides so smoothly that dark feathers can make even bright water feel dramatic. It turns quiet lakes into something more mysterious.'),
    ('en', 'blackbuck', 'The spiraled sprint antelope animal', 'The Blackbuck moves like a spring with legs, exploding into long graceful jumps across open ground. Its body is all about speed, lightness, and seeing the plain before danger sees it.'),
    ('en', 'blobfish', 'The soft-pressure deep animal', 'The Blobfish looks odd to us because it is built for crushing deep-sea pressure, not for life near the surface. In its real home, that soft body makes much more sense.'),
    ('en', 'blue-ringed-octopus', 'The tiny blue-warning animal', 'The Blue-ringed Octopus is small enough to overlook until its glowing rings appear. It shows that some of the strongest warnings come in the smallest packages.'),
    ('en', 'blue-tongued-skink', 'The blue-tongue bluff animal', 'The Blue-tongued Skink may look calm and sleepy, but when scared it flashes a bright tongue like a sudden warning sign. Surprise can be a defense all by itself.'),
    ('en', 'blue-whale', 'The giant blue ocean animal', 'The Blue Whale is so large it changes your idea of size, yet it lives by filtering tiny food from the sea. It shows that something immense can still depend on very small things done at huge scale.'),
    ('en', 'bluefin-tuna', 'The endless blue sprint animal', 'The Bluefin Tuna is a strong sleek fish built for long fast swims across the open ocean. It keeps going for huge distances, proving that stamina can be just as important as speed.'),
    ('en', 'boa-constrictor', 'The quiet coil-power animal', 'The Boa Constrictor does not need claws, legs, or speed. It waits, blends in, and lets its body become the trap.'),
    ('en', 'bombardier-beetle', 'The chemical surprise bug animal', 'The Bombardier Beetle carries a tiny chemistry lab inside its body. When danger comes too close, it answers with a hot noisy blast instead of trying to wrestle.'),
    ('en', 'brown-pelican', 'The dive-bomb fisher animal', 'The Brown Pelican turns the sky into a fishing platform. It spots a fish, folds up, and drops like a feathery spear before scooping the water with its giant bill.'),
    ('en', 'burmese-python', 'The giant coil ambush animal', 'The Burmese Python does not chase with speed or noise. It lets pattern, patience, and pure body strength solve the problem instead.'),
    ('en', 'burrowing-owl', 'The ground-hole owl animal', 'The Burrowing Owl breaks the rules people expect from owls. It lives in the ground, hunts in daylight, and makes open country feel like a place for little watchtowers.'),
    ('en', 'bushmaster', 'The leaf-shadow viper animal', 'The Bushmaster disappears so well into the forest floor that it almost becomes part of the leaves. It is a reminder that the ground itself can hide a powerful answer.'),
    ('en', 'caiman-lizard', 'The snail-crushing river animal', 'The Caiman Lizard looks armored because much of its world is rough, wet, and full of shelled prey. It is built to crack hard food in places where land and water overlap.'),
    ('en', 'california-condor', 'The sky-cleaning cliff giant animal', 'The California Condor is a giant soaring bird that finds dead animals and helps clean the land. It survived only because people worked hard to keep this sky giant from disappearing forever.'),
    ('en', 'california-quail', 'The topknot runner animal', 'The California Quail looks charming with its little head plume, but it lives by staying close to cover and close to the covey. Small birds survive better when nobody wanders too far alone.'),
    ('en', 'canada-goose', 'The honking sky-arrow animal', 'The Canada Goose flies in loud moving V shapes that help the flock travel together. It shows that long-distance teamwork can be heard before it is seen.'),
    ('en', 'canada-lynx', 'The snowshoe forest cat animal', 'The Canada Lynx is a cold-country cat with oversized furry feet that help it walk on snow. It is built like a quiet winter hunter shaped by deep forests and deep drifts.'),
    ('en', 'cane-toad', 'The big warty toad animal', 'The Cane Toad is built like a squat little tank, not a graceful jumper. It survives by being tough, adaptable, and hard to mess with.'),
    ('en', 'capybara', 'The calm riverside peace-holder animal', 'The Capybara is the biggest rodent in the world and loves to sit near rivers and ponds. It stays calm because it knows water is close if it needs a quick escape.'),
    ('en', 'caracal', 'The tuft-eared leap hunter animal', 'The Caracal is a smooth red cat with tall black ear tufts and a huge jump. It turns quick springing power into surprise, especially when birds or small animals try to escape.'),
    ('en', 'chambered-nautilus', 'The spiral depth-tuning elder animal', 'The Nautilus is a sea creature with a beautiful curly shell that works like a little submarine. Inside its shell are tiny rooms that help it float up high or sink down deep, and it moves slowly through reef water looking for food.'),
    ('en', 'chameleon', 'The still color-shifting watcher animal', 'The Chameleon is a slow climbing lizard with eyes that can look in different directions. It likes to stay still, blend in, and shoot out its tongue when the bug is close enough.'),
    ('en', 'cheetah', 'The pure burst-speed arrow animal', 'The Cheetah is the fastest land animal and can burst across the grass like a striped arrow. Because speed takes a lot of energy, it saves its fastest run for the right moment.'),
    ('en', 'chimpanzee', 'The clever tribe-making animal', 'The Chimpanzee is a smart ape that uses sticks, stones, and teamwork to solve problems. It reminds us that hands and minds grow stronger when they work together.'),
    ('en', 'chinese-crocodile-lizard', 'The dragon-stream relic animal', 'The Chinese Crocodile Lizard looks like a tiny dragon from an old painting, but it lives quietly along cool forest streams. Its world is narrow, which makes protecting it especially important.'),
    ('en', 'chinese-giant-salamander', 'The ancient river-bottom giant animal', 'The Chinese Giant Salamander is one of the biggest amphibians on Earth and lives in cool streams. It is an ancient animal that seems to carry very old river secrets with it.'),
    ('en', 'chinese-softshell-turtle', 'The mud-hiding snorkel animal', 'The Softshell Turtle hides in mud with only its tiny nose showing, almost like the pond grew a breathing straw. It turns softness and flatness into a sneaky advantage.'),
    ('en', 'cicada', 'The underground time-bomb singer animal', 'The Cicada lives underground for years and then comes out all at once to sing loudly in the trees. It shows that timing can be a powerful kind of magic.'),
    ('en', 'clownfish', 'The anemone-house alliance animal', 'The Clownfish lives among the waving arms of a sea anemone without getting stung. Because it understands that prickly home, danger becomes shelter.'),
    ('en', 'coati', 'The ring-tailed sniffer animal', 'The Coati uses its long nose like a little detector while it climbs, digs, and searches with its group. It makes the forest floor and branches feel connected by curiosity.'),
    ('en', 'coconut-crab', 'The island claw titan animal', 'The Coconut Crab is a giant land crab with claws strong enough to open very hard food. It turns island rocks and trees into its own rugged climbing world.'),
    ('en', 'coelacanth', 'The ancient deep-sea relic animal', 'The Coelacanth was once thought gone forever, then it appeared again from deep water like a living fossil. It feels like a message from another age still swimming quietly below.'),
    ('en', 'common-genet', 'The spotted moon climber animal', 'The Genet is slim, spotted, and so light on branches that it almost seems poured into the night. It uses length, balance, and stealth instead of bulk.'),
    ('en', 'common-kingfisher', 'The blue lightning river-dart animal', 'The Kingfisher is a small blue-and-orange bird that watches water carefully from a branch. Then it shoots down like a spark to catch a fish.'),
    ('en', 'common-loon', 'The haunting lake diver animal', 'The Loon is a sleek water bird with a voice that makes quiet lakes sound mysterious. It dives deeply for fish and seems to disappear into the dark water itself.'),
    ('en', 'common-potoo', 'The ghost-branch bird animal', 'The Potoo sits so still on a branch that it looks like broken wood with eyes. It turns silence and shape into one of the strangest hiding tricks in the forest.'),
    ('en', 'common-raven', 'The black air trickster animal', 'The Raven is a smart black bird that can soar, play, and solve problems with impressive calm. It makes the sky feel like a place for both thinking and mischief.'),
    ('en', 'corn-snake', 'The red-patterned field animal', 'The Corn Snake slips through barns, brush, and warm ground with an easy flowing motion. It shows how a simple body can solve a lot of spaces.'),
    ('en', 'cougar', 'The silent wide-range jumper animal', 'The Cougar is a big cat that can live in mountains, forest, or dry country as long as it has room and cover. It keeps its power quiet until one huge jump changes everything.'),
    ('en', 'crocodile', 'The patient bottleneck ambush ruler animal', 'The Crocodile is a huge reptile that waits in rivers and swamps with only its eyes above the water. It shows how being patient in the right place can be stronger than rushing everywhere.'),
    ('en', 'crow', 'The clever urban puzzle solver animal', 'The Crow is a clever black bird that remembers faces and solves little problems like puzzles. It shows that a smart mind can turn almost anything into a useful tool.'),
    ('en', 'cuban-crocodile', 'The island swamp snapper animal', 'The Cuban Crocodile is fast, powerful, and tied to a very small part of the world. It shows how a strong design can still become fragile when the map gets tiny.'),
    ('en', 'cuttlefish', 'The living color-screen illusion animal', 'The Cuttlefish is a smart sea animal that can change the color and pattern of its skin in a flash. It uses its body like a living screen to hide, hunt, or send a message.'),
    ('en', 'demoiselle-crane', 'The silver steppe dancer animal', 'The Demoiselle Crane looks delicate, but it travels huge distances and crosses hard country with calm grace. It reminds us that elegance can also be strong.'),
    ('en', 'desert-rain-frog', 'The squeaky sand frog animal', 'The Desert Rain Frog looks like a tiny grumpy bubble with legs, but it is built for one very specific sandy world. Sometimes surviving means fitting one place perfectly.'),
    ('en', 'dolphin', 'The echo-guided pod genius animal', 'The Dolphin is a playful sea mammal that uses clicks and echoes to find its way and hunt fish. It can listen to the water like a map even when it cannot see clearly.'),
    ('en', 'double-crested-cormorant', 'The black water diver animal', 'The Cormorant dives deep after fish and then stands with wings spread as if hanging its coat to dry. It looks like a bird that knows exactly what water costs.'),
    ('en', 'dragonfly', 'The ancient air-target ace animal', 'The Dragonfly is a shining flying hunter that can zip, stop, and turn in the air with amazing control. It moves like it already knows exactly where it wants to go.'),
    ('en', 'dromedary-camel', 'The heat-crossing desert ship animal', 'The Dromedary Camel is made for hot empty places where water and shade are hard to find. Its feet, nose, and body all help it travel far where many animals would struggle.'),
    ('en', 'dugong', 'The seagrass moon-grazer animal', 'The Dugong is a shy sea mammal that spends its life grazing on underwater grass. It shows how one calm eater can depend completely on a healthy ocean meadow.'),
    ('en', 'dung-beetle', 'The rolling waste-to-gold animal', 'The Dung Beetle is a little bug that rolls animal poop into a ball and carries it away. It may seem messy, but this hard work helps clean the land and feed the soil.'),
    ('en', 'dwarf-caiman', 'The small armored river animal', 'The Dwarf Caiman is a compact crocodilian that keeps the same ancient body plan in a smaller package. It hides in forest water where armor and patience still do the job.'),
    ('en', 'eagle', 'The high thermal vision king animal', 'The Eagle is a strong bird with wide wings and eyes built for looking far below. It likes to rise high, choose the best moment, and swoop down when it is ready.'),
    ('en', 'eastern-newt', 'The shape-changing pond animal', 'The Eastern Newt changes so much as it grows that it almost seems like two different creatures in one life. It shows that growing up can mean changing both body and home.'),
    ('en', 'egyptian-cobra', 'The hooded warning serpent animal', 'The Egyptian Cobra can lift up and spread its hood so the warning arrives before the strike. It shows how shape can become message in an instant.'),
    ('en', 'electric-eel', 'The lightning river animal', 'The Electric Eel turns its own body into a power source, sending shocks through dark muddy water. It proves that sensing and stunning can become the same move.'),
    ('en', 'elephant', 'The heavy ancestral memory keeper animal', 'The Elephant is a giant animal with a long trunk, huge feet, and a very good memory. It remembers safe paths, water places, and family voices, almost like it carries an old map inside its head.'),
    ('en', 'elk', 'The bugling mountain herd animal', 'The Elk is a giant deer with a voice that can roll across valleys like a trumpet. It shows how travel, timing, and a powerful call can turn open land into one shared stage.'),
    ('en', 'emerald-tree-boa', 'The branch-loop jewel animal', 'The Emerald Tree Boa hangs on branches like a living piece of green rope with bright white markings. Its color makes the forest canopy feel like home instead of a maze.'),
    ('en', 'emperor-penguin', 'The winter huddle endurance animal', 'The Emperor Penguin is a tall penguin that lives in the freezing Antarctic cold. When the wind gets fierce, penguins huddle close and share warmth like a living blanket.'),
    ('en', 'emperor-scorpion', 'The black pincer armor animal', 'The Emperor Scorpion looks fierce, but it often wins by posture, armor, and giant claws before the tail even matters. It turns darkness into a place where calm confidence works.'),
    ('en', 'emu', 'The shaggy outback runner animal', 'The Emu turns big open country into a walking and running world. It may not fly, but its legs make the ground itself into its advantage.'),
    ('en', 'european-hedgehog', 'The spiky night wanderer animal', 'The Hedgehog is a tiny nighttime explorer with a coat of spikes instead of fur on its back. When trouble comes too close, it turns into a little prickly ball.'),
    ('en', 'european-robin', 'The orange-breasted garden animal', 'The Robin is a tiny bird with a glowing orange chest that seems almost painted on. It feels friendly and close, but it still works hard all day to find food and guard space.'),
    ('en', 'european-roller', 'The blue tumble bird animal', 'The Roller flashes bright blue through warm open country and spins in the air during display. It turns even a short flight into a sudden burst of theater.'),
    ('en', 'fennec-fox', 'The big-eared desert listener animal', 'The Fennec Fox is a tiny desert fox with giant ears that help it hear and stay cool. In a hot hard place, good listening can be even better than big muscles.'),
    ('en', 'fire-salamander', 'The yellow-marked forest animal', 'The Fire Salamander looks as though a little flame pattern was painted on wet black skin. Its bright marks are not decoration alone; they are part of the warning.'),
    ('en', 'firefly', 'The tiny light-code signal animal', 'The Firefly is a tiny bug that makes its own light blink in the dark. It shows that even a very small light can still help others find the way.'),
    ('en', 'flying-dragon', 'The parachute lizard animal', 'The Flying Dragon opens wing-like flaps on its ribs and glides from tree to tree like a living paper airplane. It solves the forest not by climbing more, but by falling smarter.'),
    ('en', 'fossa', 'The island shadow predator animal', 'The Fossa moves through Madagascar''s trees and ground with the smooth confidence of an animal made for both. It shows what happens when an island writes its own top hunter.'),
    ('en', 'frilled-lizard', 'The sudden fear-flare runner animal', 'The Frilled Lizard is a little reptile with a big neck frill that pops open like a surprise umbrella. When it feels scared, that sudden flash can make an enemy think twice.'),
    ('en', 'gaboon-viper', 'The leaf-litter fang animal', 'The Gaboon Viper can disappear into fallen leaves so well that the ground itself seems to become dangerous. It shows that stillness and pattern can be stronger than chasing.'),
    ('en', 'galapagos-tortoise', 'The ancient island tank animal', 'The Galapagos Tortoise is a giant reptile that walks slowly and lives for a very long time. It turns patience into a whole way of being, one careful step at a time.'),
    ('en', 'gentoo-penguin', 'The white-brow swimmer animal', 'The Gentoo Penguin waddles on land, but in the water it becomes one of the fastest penguins. It proves that awkward on one surface can mean perfect on another.'),
    ('en', 'giant-anteater', 'The long-snouted nest opener animal', 'The Giant Anteater has a nose like a tube and claws like digging hooks for breaking into insect cities. It does not need teeth because its sticky tongue does the catching.'),
    ('en', 'giant-clam', 'The living reef vault animal', 'The Giant Clam looks like a treasure chest growing out of the reef. It stays in one place and lets sunlight help power part of its life, almost like a living solar machine.'),
    ('en', 'giant-pacific-octopus', 'The giant thinking tentacle animal', 'The Giant Pacific Octopus can squeeze, hide, feel, and solve its way through a hard underwater world. It is like eight clever hands connected to one deep-sea mind.'),
    ('en', 'giant-panda', 'The peaceful bamboo strength animal', 'The Giant Panda is a big black-and-white bear that spends much of its time eating bamboo. It shows that a peaceful simple life can still be strong and special.'),
    ('en', 'giant-water-bug', 'The underwater grabber animal', 'The Giant Water Bug is a pond hunter that waits underwater with grabbing arms ready. It turns still water into a surprise world where insects can act like little monsters.'),
    ('en', 'gila-monster', 'The beaded desert warning animal', 'The Gila Monster does not rush. Its bright pattern warns others, and its thick body carries what it needs through tough dry country.'),
    ('en', 'giraffe', 'The tall far-seeing grazer animal', 'The Giraffe is the tallest land animal, with a long neck that reaches leaves high in the trees. Its great height lets it see farther and find food other animals cannot reach.'),
    ('en', 'glass-frog', 'The transparent leaf-shadow spirit animal', 'The Glass Frog is a small green frog with skin so clear that you can sometimes see inside its body. It hides well on leaves because it looks light, delicate, and hard to notice.'),
    ('en', 'goblin-shark', 'The deep-sea lance animal', 'The Goblin Shark looks like a creature imagined from a nightmare of the deep, but every strange part helps in darkness. Its projecting jaws turn surprise into a weapon.'),
    ('en', 'golden-pheasant', 'The painted woodland animal', 'The Golden Pheasant looks almost too bright for the forest, but it spends much of its life close to the ground in cover. It shows that dazzling color can hide behind careful behavior.'),
    ('en', 'great-blue-heron', 'The still-water spear master animal', 'The Great Blue Heron is a tall blue-gray bird that stands very still beside water. It waits patiently until the perfect second and then grabs a fish with its sharp beak.'),
    ('en', 'great-egret', 'The white marsh spear animal', 'The Great Egret turns stillness into a hunting tool. It stands so quietly in shallow water that the next movement feels like lightning.'),
    ('en', 'great-white-pelican', 'The giant scoop-bill animal', 'The Pelican is a huge bird with a stretchy bill pouch that works like a fish net. When pelicans fish together, the water becomes part of the teamwork.'),
    ('en', 'great-white-shark', 'The sharp-sensed apex torpedo animal', 'The Great White Shark is a strong fast hunter with sharp senses that can notice movement, smell, and electrical signals in the water. Its power comes from many parts working together, not from teeth alone.'),
    ('en', 'greater-bird-of-paradise', 'The dazzling dance-display spirit animal', 'The Greater Bird-of-paradise is famous for its shining feathers and dancing displays in the trees. It shows that sometimes movement and beauty are part of the message.'),
    ('en', 'greater-flamingo', 'The pink salt-water filter animal', 'The Greater Flamingo is a tall pink bird that sweeps tiny food from shallow salty water. It shows that lots of little things can build something big and bright.'),
    ('en', 'greater-roadrunner', 'The desert sprint hunter animal', 'The Roadrunner is a desert bird that spends more time running than flying. It turns hot dry ground into a racecourse for catching lizards, insects, and even snakes.'),
    ('en', 'green-anaconda', 'The river-thick constricting titan animal', 'The Green Anaconda is a giant snake that lives in rivers and wetlands in South America. The water helps carry its heavy body, making its huge size easier to use.'),
    ('en', 'green-sea-turtle', 'The ancient ocean garden-keeper animal', 'The Green Sea Turtle is a gentle ocean traveler that eats seagrass in shallow water. By trimming those underwater meadows, it helps keep them healthy and growing.'),
    ('en', 'green-tree-python', 'The branch-perched emerald animal', 'The Green Tree Python waits on branches like a bright green question mark. It shows how a tree can become both chair and hunting platform at the same time.'),
    ('en', 'guanaco', 'The windland runner animal', 'The Guanaco travels through big windy spaces where the land feels open and endless. It is built for distance, alertness, and keeping the herd moving together.'),
    ('en', 'harbor-seal', 'The tide-resting fish hunter animal', 'The Harbor Seal slips through coastal water like a smooth little torpedo and then naps on rocks when the tide is right. It shows how a good day can swing between quiet rest and sharp hunting.'),
    ('en', 'harpy-eagle', 'The jungle talon king animal', 'The Harpy Eagle is one of the strongest forest birds on Earth, with claws built like giant hooks. It flies through dense jungle where raw grip and surprise matter more than open-sky speed.'),
    ('en', 'hawksbill-sea-turtle', 'The reef-beaked turtle animal', 'The Hawksbill uses a narrow beak to reach food hidden deep in reef spaces. It is one of those animals that seems beautiful because it is perfectly matched to a complex habitat.'),
    ('en', 'hellbender', 'The flat-rock river keeper animal', 'The Hellbender is a big flat salamander that hides under rocks in cold clean streams. When a river stays healthy and clear, quiet animals like this can keep living there.'),
    ('en', 'hippopotamus', 'The river-heavy wall animal', 'The Hippopotamus is a giant animal that spends much of the day cooling off in water and much of the night eating grass. It looks sleepy, but it carries huge power in a very solid body.'),
    ('en', 'hoatzin', 'The swamp-forest oddball animal', 'The Hoatzin looks like a bird from another age and eats leaves in a way more like a tiny cow than a typical bird. It proves that nature is not afraid of strange solutions.'),
    ('en', 'honey-badger', 'The fearless dig-and-take animal', 'The Honey Badger is a tough little predator that digs, tears, and pushes into places other animals avoid. It teaches that bravery works best when it is backed by real tools.'),
    ('en', 'honey-bee', 'The sacred flower-routing hive animal', 'The Honey Bee is a fuzzy little worker that gathers nectar and pollen from flowers. When it finds something good, it goes home and tells the hive where to go.'),
    ('en', 'hoopoe', 'The crowned ground-probing oracle animal', 'The Hoopoe is a bird with a crown of feathers and a long beak for poking into the ground. It finds hidden bugs by looking where other animals forget to search.'),
    ('en', 'horned-lizard', 'The spiky pancake lizard animal', 'The Horned Lizard stays low, flat, and thorny, like a little piece of desert that came alive. Its shape helps it hide and handle the hard hot ground.'),
    ('en', 'horseshoe-crab', 'The ancient beach armor animal', 'The Horseshoe Crab looks like a creature from another age because it almost is one. Its strange shell and beach-spawning life make it feel like the ocean still remembers very old designs.'),
    ('en', 'humpback-whale', 'The singing ocean traveler animal', 'The Humpback Whale is a giant singer that travels huge distances between cold feeding water and warm breeding seas. It turns the ocean into a road and a concert hall at the same time.'),
    ('en', 'indian-peafowl', 'The radiant display signal animal', 'The Indian Peafowl is a bright bird with a giant fan of shining tail feathers. Its beautiful display is a way of talking without words and saying, ''Look at me.'''),
    ('en', 'indian-star-tortoise', 'The star-shell grazer animal', 'The Indian Star Tortoise carries a shell that looks like little suns painted on dark domes. Even its beauty works as broken pattern in dry grass and thorny ground.'),
    ('en', 'jellyfish', 'The drifting soft-sting pulse animal', 'The Jellyfish is a soft drifting sea animal with stinging arms. It lets the water carry it, showing that sometimes moving with the flow is the smartest choice.'),
    ('en', 'jumping-spider', 'The tiny precision leap hunter animal', 'The Jumping Spider is a tiny hunter with big eyes and a brave jump. It does not need to be large because it aims carefully and leaps at just the right moment.'),
    ('en', 'kakapo', 'The rare green night-parrot animal', 'The Kakapo is a big green parrot that forgot how to fly but learned how to climb and hide instead. It is so rare that every bird feels like a tiny national treasure.'),
    ('en', 'king-cobra', 'The tall venom sovereign serpent animal', 'The King Cobra is a long powerful snake that eats other snakes and can lift the front of its body high off the ground. It shows that being really good at one hard thing can be a special kind of power.'),
    ('en', 'king-penguin', 'The royal cold-ocean animal', 'The King Penguin stands tall in the cold and disappears into the sea for food with smooth confidence. On land it is part of a crowd, but in water it becomes a quiet torpedo.'),
    ('en', 'kinkajou', 'The honey-eyed canopy animal', 'The Kinkajou climbs through the nighttime forest with a tail that works like another hand. It turns the treetops into a soft dark playground full of fruit and flowers.'),
    ('en', 'kiwi', 'The nose-tipped forest bird animal', 'The Kiwi is a shy night bird that sniffs the ground with a long bill to find worms and bugs. It shows that you do not need wings to become one of the most special birds on Earth.'),
    ('en', 'koala', 'The sleepy eucalyptus dream animal', 'The Koala is a fluffy tree animal that spends much of the day sleeping and eating eucalyptus leaves. It lives slowly because its food gives it only a little energy.'),
    ('en', 'komodo-dragon', 'The patient island apex force animal', 'The Komodo Dragon is a giant lizard from hot islands in Indonesia. It likes to wait, watch, and use its big strength only when the moment is right.'),
    ('en', 'laughing-kookaburra', 'The laughing branch-top ambusher animal', 'The Laughing Kookaburra is a chunky bird with a call that sounds like loud happy laughter. Even with that silly voice, it is a sharp hunter that watches carefully from a branch.'),
    ('en', 'leafcutter-ant', 'The farming fungus empire animal', 'The Leafcutter Ant carries pieces of leaves into underground rooms, but not to eat them right away. It grows fungus like a tiny farmer, making its own food garden below the ground.'),
    ('en', 'leafy-seadragon', 'The seaweed ghost animal', 'The Leafy Seadragon looks as if a piece of floating seaweed learned to swim. It survives by becoming so perfectly plant-like that the water almost stops noticing it.'),
    ('en', 'leatherback-sea-turtle', 'The deep-ocean giant turtle animal', 'The Leatherback is the largest sea turtle and can dive into the deep dark ocean after drifting prey. It feels less like a beach turtle and more like a living ocean vessel.'),
    ('en', 'leopard', 'The quiet everywhere survivor animal', 'The Leopard is a spotted big cat that can climb, hide, and hunt in many different places. It stays alive by being quiet, flexible, and ready for almost anything.'),
    ('en', 'leopard-gecko', 'The spotted twilight hide-master animal', 'The Leopard Gecko is a small spotted lizard with bright eyes and a gentle way of moving. It survives by hiding well, coming out at the right time, and not wasting energy.'),
    ('en', 'lion', 'The calm solar pride ruler animal', 'The Lion is a powerful big cat that lives with a pride on open land. It does not need to fight all the time because real strength knows when to rest and when to act.'),
    ('en', 'lionfish', 'The beautiful venom invasion animal', 'The Lionfish is a beautiful striped fish with long spiky fins and venomous points for protection. In the wrong reef it can spread too fast, showing that even pretty things can cause big trouble.'),
    ('en', 'llama', 'The highland wool carrier animal', 'The Llama is a mountain animal with soft wool and strong feet for steep ground. It carries loads, watches its herd, and handles thin air better than many lowland animals could.'),
    ('en', 'loggerhead-sea-turtle', 'The big-headed sea traveler animal', 'The Loggerhead carries a huge head for cracking hard prey and a life built around enormous journeys. It belongs to the sea, but it always returns to land to begin the next generation.'),
    ('en', 'maine-coon-cat', 'The gentle winter giant animal', 'The Maine Coon is a huge fluffy cat with tufted ears and a long bushy tail. It is built for cold weather and feels like a soft blanket with paws.'),
    ('en', 'malayan-tapir', 'The moonlit forest path-maker animal', 'The Malayan Tapir is a shy forest animal with a black-and-white body and a little trunk-like nose. It moves quietly at night, eating plants and carrying seeds through the jungle.'),
    ('en', 'manatee', 'The gentle seagrass grazer animal', 'The Manatee is a slow peaceful water giant that spends much of its day eating plants. It drifts through warm rivers and coasts like a floating lawn mower for the underwater garden.'),
    ('en', 'mandarin-duck', 'The painted pond duck animal', 'The Mandarin Duck looks like a tiny floating festival of feathers. But behind the bright colors is a bird that knows woodland water, hidden nests, and careful flight.'),
    ('en', 'mandrill', 'The painted forest monarch animal', 'The Mandrill looks like someone painted a face onto a powerful monkey body. Its colors are dramatic, but its real world is about troop life, forest movement, and social rank.'),
    ('en', 'maned-wolf', 'The red grass walker animal', 'The Maned Wolf looks like a fox on stilts because its long legs help it move through tall grass and see over it. It lives alone and lets the open land do part of the hiding.'),
    ('en', 'manta-ray', 'The flying filter-wing ocean animal', 'The Manta Ray is a huge flat sea animal that glides through water like a bird in the sky. It opens its mouth as it swims to filter tiny food from the sea.'),
    ('en', 'mantis-shrimp', 'The rainbow hammer strike animal', 'The Mantis Shrimp is a bright sea hunter with amazing eyes and a punch faster than you can see. It keeps its power ready inside like a spring and then lets it snap.'),
    ('en', 'mantled-howler-monkey', 'The thunder-throat tree animal', 'The Howler Monkey does not need to be seen to be noticed. Its voice rolls through the forest like thunder, turning trees into a speaker system.'),
    ('en', 'marine-iguana', 'The sea-grazing lava lizard animal', 'The Marine Iguana is a lizard from the Galapagos that swims into the sea to eat algae from rocks. It is special because it learned to live where most lizards never go.'),
    ('en', 'markhor', 'The spiral-horn cliff animal', 'The Markhor climbs broken mountain walls with the calm balance of something born from the rocks. Its twisting horns make it look almost mythical, but its real magic is footing.'),
    ('en', 'mata-mata-turtle', 'The leaf-face ambush animal', 'The Mata Mata Turtle looks like a floating pile of leaves until it suddenly inhales prey with a fast gulp. It turns looking messy and strange into a perfect hiding plan.'),
    ('en', 'meerkat', 'The upright shared-watch scout animal', 'The Meerkat is a small desert animal that likes to stand up tall and look around. One meerkat watches while the others dig or eat, so the whole group stays safer.'),
    ('en', 'monarch-butterfly', 'The royal migration map animal', 'The Monarch Butterfly is a bright orange butterfly that travels huge distances on delicate wings. It shows that even something small can carry a giant journey inside it.'),
    ('en', 'moose', 'The towering swamp forest animal', 'The Moose is a giant deer with long legs for stepping through snow, mud, and water. It reaches plants in wet places and carries the forest on a very tall frame.'),
    ('en', 'moray-eel', 'The reef-hole ribbon animal', 'The Moray Eel hides in cracks in the reef with its mouth open, making the rocks seem alive. It turns tight spaces into safe rooms and ambush points all at once.'),
    ('en', 'mountain-goat', 'The white cliff dancer animal', 'The Mountain Goat walks narrow ledges as if the mountain were built just for it. Its white coat and perfect feet turn cold dangerous heights into home.'),
    ('en', 'mudpuppy', 'The water-gilled night animal', 'The Mudpuppy is a salamander that keeps its feathery gills even as an adult and lives underwater all the time. It slips through cool dark water like a little river dragon.'),
    ('en', 'musk-ox', 'The wool-wall tundra animal', 'The Musk Ox wears one of the warmest coats in the Arctic and stands together with the herd when danger comes. It survives by turning cold and teamwork into armor.'),
    ('en', 'narwhal', 'The spiral-ice unicorn animal', 'The Narwhal is a whale with a long spiraling tusk that looks like something from a storybook. It lives in cold icy seas where deep dives and careful travel are part of everyday life.'),
    ('en', 'nicobar-pigeon', 'The rainbow island pigeon animal', 'The Nicobar Pigeon shines with green and blue metal-like feathers, but much of its life is about island hopping and careful ground feeding. It feels like a jewel that learned to travel.'),
    ('en', 'nile-monitor', 'The riverbank lizard engine animal', 'The Nile Monitor is a long powerful lizard that can climb, dig, swim, and raid. It makes any place near water feel like a zone full of possibilities.'),
    ('en', 'nine-banded-armadillo', 'The armored dig-and-hide animal', 'The Armadillo wears hard plates like built-in armor and spends a lot of time digging for bugs. It stays low, moves quickly, and lets its strange shell do part of the protecting.'),
    ('en', 'north-american-beaver', 'The river engineer builder animal', 'The Beaver changes whole streams with sticks, mud, and patient work. By building dams and ponds, it makes new watery homes for many other creatures too.'),
    ('en', 'north-american-raccoon', 'The masked night tinkerer animal', 'The Raccoon is a smart night animal with paws that work almost like little hands. It can open, grab, and explore its way through all kinds of places.'),
    ('en', 'northern-cardinal', 'The red backyard singer animal', 'The Cardinal is a bright red bird that makes bushes and gardens feel suddenly louder and more colorful. It is small, but its song carries like it thinks the whole yard should listen.'),
    ('en', 'northern-gannet', 'The spear-diving seabird animal', 'The Gannet turns height into speed, folding itself and plunging into the sea like a feathered arrow. It shows how the sky can become a tool for hunting underwater food.'),
    ('en', 'northern-tamandua', 'The climbing ant vacuum animal', 'The Tamandua climbs, hugs branches, and tears open insect nests with hooked claws. It turns a simple body plan into a very specific and very successful job.'),
    ('en', 'numbat', 'The striped termite finder animal', 'The Numbat is a tiny striped marsupial with a long tongue for catching termites. It spends the day hunting little insects in logs and soil like a careful bug detective.'),
    ('en', 'ocean-sunfish', 'The floating disc animal', 'The Ocean Sunfish looks like half a fish and twice the mystery. It drifts, swims, and basks in a way that makes the open ocean feel full of impossible shapes.'),
    ('en', 'ocelot', 'The moonlit rosette shadow animal', 'The Ocelot is a patterned forest cat that slips through thick cover like moving leaves. Its beautiful coat is really a hiding tool painted in jungle colors.'),
    ('en', 'octopus', 'The fluid escape artist thinker animal', 'The Octopus is a smart sea animal with eight arms and a squishy body that can squeeze through tiny spaces. When a problem appears, it can change color, change shape, and think of a new escape.'),
    ('en', 'okapi', 'The striped forest whisper animal', 'The Okapi looks like a secret mix of deer, zebra, and giraffe, but it is its own quiet forest wonder. It hides in dark rainforest and browses leaves with a tongue almost too long to believe.'),
    ('en', 'olm', 'The cave-river ghost animal', 'The Olm lives in underground water where sunlight never reaches. Pale, blind, and patient, it feels like a creature shaped by silence itself.'),
    ('en', 'orangutan', 'The slow wise canopy builder animal', 'The Orangutan is a long-armed forest ape that swings, climbs, and makes careful choices in the trees. It learns slowly and deeply, like it is studying the jungle one branch at a time.'),
    ('en', 'orca', 'The black-and-white tide hunter animal', 'The Orca is a giant ocean hunter that works with family to chase, trap, and outthink prey. It shows that teamwork can become a kind of superpower in the sea.'),
    ('en', 'orchid-mantis', 'The flower-disguised trap artist animal', 'The Orchid Mantis looks so much like a flower that other insects can be fooled by it. What seems beautiful and harmless can sometimes be a very clever trap.'),
    ('en', 'osprey', 'The fish-diving sky hunter animal', 'The Osprey is a bird of prey that treats the water like a target board. It hangs, aims, and drops feet-first to grab fish with built-in hooks.'),
    ('en', 'ostrich', 'The giant running bird animal', 'The Ostrich does not fly, but it does not need to. Its long legs turn open land into a racetrack, and its huge eyes help it see trouble from far away.'),
    ('en', 'peacock-spider', 'The tiny dancing jewel animal', 'The Peacock Spider is so small you might overlook it, but the males put on one of the wildest dances in nature. It proves that tiny size does not mean tiny drama.'),
    ('en', 'peregrine-falcon', 'The falling sky-bullet hunter animal', 'The Peregrine Falcon is one of the fastest animals on Earth and dives through the sky like a living dart. It lets gravity help it, so the fall becomes part of the power.'),
    ('en', 'pileated-woodpecker', 'The red-crested tree drummer animal', 'The Pileated Woodpecker turns a tree trunk into a drum and a doorway at the same time. Its hammering opens hidden insects and also makes homes other creatures can use later.'),
    ('en', 'plains-zebra', 'The striped confusion shield animal', 'The Plains Zebra is a horse-like animal covered in black-and-white stripes. When zebras move together, their stripes can blur into one wiggly pattern that confuses danger.'),
    ('en', 'platypus', 'The river-puzzle bill animal', 'The Platypus looks like several animals mixed together, but every odd piece helps it in the water. Its bill senses tiny signals, and its body slips through streams like a furry little submarine.'),
    ('en', 'poison-dart-frog', 'The bright warning drop animal', 'The Poison Dart Frog is tiny and brightly colored, like a living warning sign. Its colors tell other animals, ''Do not touch me.'''),
    ('en', 'polar-bear', 'The ice-platform endurance hunter animal', 'The Polar Bear is a giant white bear that hunts on sea ice in the Arctic. It depends on that icy floor, so when the ice changes, its whole hunting life changes too.'),
    ('en', 'portuguese-man-o-war', 'The stinging sail animal', 'The Portuguese Man o'' War is not one simple creature but a floating team of parts with different jobs. It lets wind, current, and long stinging lines do the work together.'),
    ('en', 'prairie-dog', 'The whistle-town builder animal', 'The Prairie Dog is a little grassland animal that lives in busy underground neighborhoods. It watches, warns, and digs so the whole colony can act like one careful town.'),
    ('en', 'praying-mantis', 'The prayer-armed patience blade animal', 'The Praying Mantis is a bug with folded arms that make it look peaceful and thoughtful. But when food comes close, it strikes with lightning-fast timing.'),
    ('en', 'proboscis-monkey', 'The river-corridor leaf sage animal', 'The Proboscis Monkey is a funny-looking monkey with a big nose and a love for river forests. It swims well and moves along the watery edges where trees and rivers meet.'),
    ('en', 'pronghorn', 'The open-plain speed animal', 'The Pronghorn is built for seeing far and running even farther across open country. It feels like the grassland made an animal whose whole body understands distance.'),
    ('en', 'pufferfish', 'The balloon defense fish animal', 'The Pufferfish may not look fierce at first, but when trouble comes it can turn into a living balloon. It shows that getting bigger very suddenly can be its own kind of shield.'),
    ('en', 'quokka', 'The smiling island hopper animal', 'The Quokka is a little hopping marsupial with a round face that often looks cheerful. It survives best where safe habitat and fewer predators give it room to bounce and browse.'),
    ('en', 'rainbow-bee-eater', 'The rainbow aerial insect-catcher animal', 'The Rainbow Bee-eater is a bright little bird that catches flying insects in midair. It is beautiful to look at, but it is also a fast and skilled hunter.'),
    ('en', 'red-crowned-crane', 'The dancing marsh spirit animal', 'The Red-crowned Crane seems to turn a wetland into a stage whenever it dances. Its long body and careful steps make grace feel as important as survival.'),
    ('en', 'red-deer', 'The antler-crowned meadow animal', 'The Red Deer is a big grass-and-forest animal that moves with the quiet power of a king in autumn. When stags roar and clash antlers, the whole landscape feels like it is listening.'),
    ('en', 'red-eyed-tree-frog', 'The red-eyed surprise shield animal', 'The Red-eyed Tree Frog is a bright green frog with giant red eyes and sticky feet for climbing. When surprised, it flashes those bold eyes and colors to buy a second to escape.'),
    ('en', 'red-footed-tortoise', 'The ember-foot walker animal', 'The Red-footed Tortoise moves slowly, but its bright legs look like little glowing embers under a dark shell. It turns patience and steady travel into a whole lifestyle.'),
    ('en', 'red-fox', 'The adaptable trickster edge-walker animal', 'The Red Fox is a bright orange hunter with sharp ears and quick feet. It changes its tricks to fit the place, which helps it live in forests, fields, and even near towns.'),
    ('en', 'red-kangaroo', 'The red desert spring-force animal', 'The Red Kangaroo is a huge jumper from the dry lands of Australia. Its strong legs and tail help it cross big open places without wasting too much energy.'),
    ('en', 'red-panda', 'The gentle cool-canopy browser animal', 'The Red Panda is a fluffy red tree animal with a striped tail and gentle face. It needs cool forests where the branches connect, like a wooden road through the mountains.'),
    ('en', 'red-squirrel', 'The treetop stash runner animal', 'The Red Squirrel is a fast branch-runner that hides food for later like a tiny forest planner. Its tail helps it balance while it turns trees into a high-speed playground.'),
    ('en', 'red-tailed-hawk', 'The red-tail lookout animal', 'The Red-tailed Hawk watches from high perches and rides warm air over open land. It shows how a good view can do half the hunting before the dive begins.'),
    ('en', 'reindeer', 'The cold-route migration animal', 'The Reindeer is a northern traveler built for snow, wind, and long journeys. Its wide feet work like winter shoes, helping whole herds keep moving across the frozen land.'),
    ('en', 'remora', 'The hitchhiking ocean animal', 'The Remora travels by attaching to bigger swimmers like a living passenger with a suction cup on its head. It shows that size is not everything if you know how to use the giant next to you.'),
    ('en', 'resplendent-quetzal', 'The cloud-forest jewel animal', 'The Quetzal looks like a piece of living emerald light drifting through foggy forest. It belongs to cloud-filled mountains where even the air feels special.'),
    ('en', 'reticulated-python', 'The patterned crushing rope animal', 'The Reticulated Python is a very long snake with a beautiful net-like pattern on its skin. It does not chase fast with claws or teeth, but wraps its body around prey with quiet power.'),
    ('en', 'rhinoceros-beetle', 'The horned lifting warrior animal', 'The Rhinoceros Beetle is a heavy shiny bug with a horn like a tiny lifting machine. Its body shape helps it push and hoist much better than you would expect.'),
    ('en', 'rhinoceros-hornbill', 'The thunder-beaked canopy courier animal', 'The Rhinoceros Hornbill is a big forest bird with a huge curved beak and a helmet-like bump on top. Its loud calls help family members stay connected across the tall trees.'),
    ('en', 'ring-tailed-lemur', 'The scented social sunbather animal', 'The Ring-tailed Lemur is a monkey-like animal with a long striped tail and a very social life. It uses smells, sounds, and body signs to keep its family together.'),
    ('en', 'roseate-spoonbill', 'The pink spoon-bill animal', 'The Spoonbill walks through shallow water swishing its strange bill from side to side like a tiny rake. Its bright pink body makes it easy to notice, but its feeding style is the real magic.'),
    ('en', 'ruby-throated-hummingbird', 'The hovering nectar jewel animal', 'The Ruby-throated Hummingbird is a tiny bird that can hover in front of flowers and sip nectar with a long tongue. It moves fast, but every little wingbeat is carefully controlled.'),
    ('en', 'sable-antelope', 'The black-horned savannah animal', 'The Sable Antelope looks elegant from a distance, but its long curved horns are built for real defense. It carries beauty and force in the same shape.'),
    ('en', 'sacred-ibis', 'The curved-bill marsh seeker animal', 'The Sacred Ibis walks through mud and shallow water with a curved bill made for finding hidden food. It turns quiet searching into a steady way of life.'),
    ('en', 'saiga-antelope', 'The steppe-nose survivor animal', 'The Saiga looks unusual because its nose helps it handle dust, cold, and hard dry wind. It belongs to a big open world where movement and survival are tied to the shape of the land itself.'),
    ('en', 'sailfish', 'The blue ocean spear animal', 'The Sailfish cuts through warm blue water with a giant sail on its back and a spear on its face. It turns speed, shape, and teamwork into one of the ocean''s sharpest hunting designs.'),
    ('en', 'satanic-leaf-tailed-gecko', 'The leaf-disguise night animal', 'The Leaf-tailed Gecko looks so much like a dead leaf that the forest almost forgets it is there. It hides by becoming part of the picture itself.'),
    ('en', 'scalloped-hammerhead', 'The wide-headed signal scanner animal', 'The Scalloped Hammerhead is a shark with a wide hammer-shaped head that helps it sense more of the world around it. Seeing and feeling more clearly helps it make smarter hunting moves.'),
    ('en', 'scarlet-macaw', 'The loud rainbow seed-scatterer animal', 'The Scarlet Macaw is a loud red, yellow, and blue parrot that flies through the rainforest in bright flashes of color. It spreads seeds as it eats fruit, almost like joy with wings.'),
    ('en', 'sea-cucumber', 'The soft seafloor recycler animal', 'The Sea Cucumber is a soft slow sea animal that crawls along the ocean floor eating bits of mess from the sand. It helps clean the seabed so the underwater world keeps working well.'),
    ('en', 'sea-krait', 'The sea-land ribbon animal', 'The Sea Krait lives between two worlds, hunting in the ocean but coming onto land to rest and nest. Its body solves the puzzle of not having to choose only one home.'),
    ('en', 'sea-otter', 'The floating shell-cracker animal', 'The Sea Otter lies on its back like a drifting little raft and uses tools to open hard food. Its thick fur and playful style help it live in cold coastal water.'),
    ('en', 'seahorse', 'The upright tidal anchor animal', 'The Seahorse is a tiny fish that swims upright and curls its tail around plants to stay steady. Holding on helps it stay calm while the water moves all around it.'),
    ('en', 'secretary-bird', 'The long-legged snake-stomper animal', 'The Secretarybird is a tall bird that hunts on the ground with long strong legs. Instead of fighting snakes where they are strongest, it uses its fast feet to stay in control.'),
    ('en', 'serval', 'The long-legged grass pouncer animal', 'The Serval is a spotted cat with giant ears and springy legs built for tall grass. It can hear a hidden rustle and jump like a loaded spring to catch it.'),
    ('en', 'shoebill', 'The prehistoric swamp stillness animal', 'The Shoebill is a huge swamp bird with a giant beak that looks almost prehistoric. It can stand still for a very long time, waiting for the right moment to strike.'),
    ('en', 'siamang', 'The duet-singing swinger animal', 'The Siamang swings through trees with long arms and fills the forest with booming duets. It turns movement and voice into one shared performance with its mate.'),
    ('en', 'sidewinder', 'The sideways sand snake animal', 'The Sidewinder moves across loose hot sand in a way that looks impossible until you see why it works. It turns one of the worst surfaces for travel into a road.'),
    ('en', 'sloth-bear', 'The shaggy termite slurper animal', 'The Sloth Bear is a shaggy insect-eating bear with long claws and a mouth built for vacuuming termites. It turns patience, smell, and digging into dinner.'),
    ('en', 'snow-goose', 'The white storm flock animal', 'The Snow Goose turns migration into weather. When thousands lift at once, the sky itself seems to change color and sound.'),
    ('en', 'snow-leopard', 'The hidden mountain ghost power animal', 'The Snow Leopard is a pale spotted cat that blends into rocky mountains like a ghost. It stays hidden so well that the cold cliffs almost seem to wear it like a coat.'),
    ('en', 'snowy-egret', 'The yellow-foot marsh animal', 'The Snowy Egret does not only wait for food; it can stir the water with bright yellow feet to make prey move. It turns elegance into action when it needs to.'),
    ('en', 'snowy-owl', 'The white wide-field watcher animal', 'The Snowy Owl sits in open country where there is nowhere to hide and sees everything anyway. Its pale body makes frozen land look like the perfect throne.'),
    ('en', 'southern-cassowary', 'The armored rainforest seed-giant animal', 'The Southern Cassowary is a giant rainforest bird with strong legs and a bright blue neck. It eats fruit and drops seeds far away, helping new trees grow across the forest.'),
    ('en', 'spanish-dancer', 'The dancing scarlet sea animal', 'The Spanish Dancer looks like a flowing red ribbon when it swims, turning the reef into an underwater theater. Even slow animals can move beautifully when the whole body becomes the motion.'),
    ('en', 'spectral-tarsier', 'The giant-eyed leap animal', 'The Tarsier looks like a creature made almost entirely of eyes and spring-loaded legs. In the dark, that is exactly what makes it work.'),
    ('en', 'sperm-whale', 'The deep-diving echo animal', 'The Sperm Whale dives into dark water so deep that sunlight can no longer help. It listens its way through the deep, proving that sound can become vision when the world goes black.'),
    ('en', 'spotted-hyena', 'The laughing bone-crushing recycler animal', 'The Hyena is a strong spotted hunter with a laugh-like call and very powerful jaws. It uses almost every bit of food it finds, so little goes to waste.'),
    ('en', 'squirrel-monkey', 'The quick jungle chatter animal', 'The Squirrel Monkey moves through branches like a burst of yellow energy with a tail behind it. In a fast group, even small animals can make the canopy feel busy and alive.'),
    ('en', 'stag-beetle', 'The antler-jawed beetle animal', 'The Stag Beetle looks like a tiny armored deer because the males carry giant jaws like antlers. Even its babies depend on old rotting wood, showing how decay can feed new life.'),
    ('en', 'strawberry-poison-dart-frog', 'The red jungle warning animal', 'The Strawberry Poison Dart Frog is tiny but impossible to ignore when its color shines through wet leaves. It pairs bold warning with unusually careful parenting.'),
    ('en', 'striped-skunk', 'The warning-striped defense animal', 'The Skunk does not hide its warning. Its black-and-white coat says, ''Think twice,'' long before it ever needs to use its famous spray.'),
    ('en', 'sulphur-crested-cockatoo', 'The loud yellow-crested animal', 'The Cockatoo is a bright white parrot with a yellow crest that pops up like a flag when it gets excited. It is noisy, clever, and impossible to ignore when a flock arrives.'),
    ('en', 'sun-bear', 'The small forest treasure-opener animal', 'The Sun Bear is the smallest bear, with a long tongue and strong claws for reaching hidden food. It is good at opening logs, nests, and tough places where tasty things are hiding.'),
    ('en', 'sunbittern', 'The hidden-wing flash animal', 'The Sunbittern seems simple until it opens its wings and reveals a dramatic painted pattern. It saves the surprise for the exact moment it might matter most.'),
    ('en', 'sunda-pangolin', 'The armored ant-eating drill animal', 'The Sunda Pangolin is covered in hard scales and curls into a ball when it feels scared. It uses long claws and a sticky tongue to break into ant and termite homes for dinner.'),
    ('en', 'superb-lyrebird', 'The echo-copy forest bird animal', 'The Lyrebird can copy chainsaws, camera clicks, and other birds so well it almost seems impossible. It turns the forest into a giant sound library carried inside one body.'),
    ('en', 'surinam-toad', 'The leaf-flat pond animal', 'The Surinam Toad is so flat and strange it almost looks like a wet fallen leaf. Its life cycle is even stranger, proving that amphibians can solve parenting in wildly different ways.'),
    ('en', 'swallow-tailed-kite', 'The fork-tailed sky dancer animal', 'The Swallow-tailed Kite floats and twists through warm air as if the sky were soft fabric. It shows that hunting can look almost effortless when the design is this clean.'),
    ('en', 'tarantula-hawk-wasp', 'The spider-stunning wasp animal', 'The Tarantula Hawk is a wasp with bright wings and a fearless mission: find a tarantula and win. It shows how a very focused strategy can look almost unbelievable from the outside.'),
    ('en', 'tasmanian-devil', 'The loud night recycler animal', 'The Tasmanian Devil is a strong little scavenger with a huge bite and a very dramatic voice. It helps clean the land by eating what other animals leave behind.'),
    ('en', 'termite', 'The hidden earth-factory builder animal', 'The Termite is a small bug that eats dead wood and lives in giant busy colonies. Tiny workers like these help turn old things into new soil and keep the ground alive.'),
    ('en', 'thorny-devil', 'The spiky ant-sipping animal', 'The Thorny Devil looks like a tiny dragon made of desert thorns, but it mainly eats ants and collects water in clever ways. It proves that small desert problems need clever desert solutions.'),
    ('en', 'three-toed-sloth', 'The slow invisible energy-saver animal', 'The Three-toed Sloth hangs upside down in the trees and moves so slowly that it almost looks like part of the branch. By being gentle and quiet, it is harder for enemies to notice.'),
    ('en', 'tiger', 'The silent striped force animal', 'The Tiger is a striped big cat that moves quietly through grass and forest before it hunts. It shows that calm focus can be stronger than making a lot of noise.'),
    ('en', 'tiger-salamander', 'The striped burrow swimmer animal', 'The Tiger Salamander spends time underground on land and returns to water when it needs to breed. It carries two worlds in one life.'),
    ('en', 'toco-toucan', 'The giant-beaked fruit courier animal', 'The Toco Toucan is a colorful bird with a giant beak that helps it reach and carry fruit. As it moves around eating, it spreads seeds like a flying fruit helper.'),
    ('en', 'tokay-gecko', 'The loud wall climber animal', 'The Tokay Gecko grips walls and tree trunks as if gravity were only a suggestion. Its bright spots and booming call make it one of the boldest little climbers in the night.'),
    ('en', 'tomato-frog', 'The bright warning blob animal', 'The Tomato Frog is round, red, and easy to notice, which is exactly the point. Its color tells other animals that touching it may not be a good idea.'),
    ('en', 'trumpeter-swan', 'The white trumpet lake animal', 'The Trumpeter Swan is a giant white water bird with a voice that sounds like a horn across the lake. It turns still water into something grand and echoing.'),
    ('en', 'tuatara', 'The ancient island timekeeper animal', 'The Tuatara looks a little like a lizard, but it is the last survivor of a far older reptile line. It feels like a living piece of deep time still walking around.'),
    ('en', 'turkey-vulture', 'The smell-finding cleanup animal', 'The Turkey Vulture glides high on warm air and finds what the land needs cleaned up next. It proves that an important job does not have to look glamorous to matter.'),
    ('en', 'vampire-squid', 'The deep-red shadow animal', 'The Vampire Squid lives where the ocean is dark and oxygen is low, a place many other animals avoid. It survives not with speed, but with strange smart adjustments to a hard invisible world.'),
    ('en', 'victoria-crowned-pigeon', 'The crowned forest walker animal', 'The Victoria Crowned Pigeon looks like a royal bird designed for the rainforest floor. Its giant lacy crest makes every step feel ceremonial.'),
    ('en', 'vicuna', 'The golden high-plateau animal', 'The Vicuna lives where the air is thin and the weather can turn sharp very fast. Its soft coat and graceful body help it survive one of the highest homes on Earth.'),
    ('en', 'wallaces-flying-frog', 'The gliding jungle parachute animal', 'Wallace''s Flying Frog is a tree frog with wide webbed feet that help it glide through the air. It does not really fly like a bird, but it can turn a fall into a smooth little sail.'),
    ('en', 'walrus', 'The tusked ice-floor animal', 'The Walrus is a huge whiskered sea mammal with long tusks and a body built for cold. It rests on ice, dives for shellfish, and turns the Arctic coast into its giant resting room.'),
    ('en', 'wandering-albatross', 'The endless wind-riding sailor animal', 'The Wandering Albatross is a giant seabird with enormous wings that ride ocean winds for days. It shows that long journeys get easier when you let the air help carry you.'),
    ('en', 'western-lowland-gorilla', 'The quiet forest strength animal', 'The Gorilla is a giant forest ape that looks powerful but usually spends its time eating, traveling, and caring for family. It shows that real strength can be calm, watchful, and gentle.'),
    ('en', 'whale-shark', 'The gentle ocean giant filter animal', 'The Whale Shark is the biggest fish in the ocean, but it mostly eats tiny food floating in the water. It proves that something huge can still move gently and peacefully.'),
    ('en', 'white-headed-vulture', 'The clean-sky carrion judge animal', 'The White-headed Vulture is a big bird that flies high and looks for animals that have already died. It helps clean the land so sickness does not spread and the wild stays healthier.'),
    ('en', 'white-stork', 'The rooftop traveler animal', 'The White Stork builds huge nests high above the ground and rides warm air across continents. It makes home and journey feel part of the same design.'),
    ('en', 'whooping-crane', 'The bugling marsh tower animal', 'The Whooping Crane is a tall white bird with a trumpet-like voice that carries across the marsh. Its story shows how careful protection can help a nearly lost species keep walking forward.'),
    ('en', 'wolf', 'The wild pack frequency leader animal', 'The Wolf is a wild dog that hunts, travels, and cares for its family as a pack. It shows that sharing a path and helping each other makes a group stronger.'),
    ('en', 'wolverine', 'The relentless cold-range survivor animal', 'The Wolverine is a tough furry hunter that can cross snow, ice, and lonely cold places. It keeps going when the land is harsh, showing that grit can be a kind of superpower.'),
    ('en', 'wombat', 'The burrow-building bulldozer animal', 'The Wombat is a chunky digging marsupial that makes deep burrows like underground rooms. It may look slow, but its body is built like a little earth-moving machine.'),
    ('en', 'wood-duck', 'The rainbow forest duck animal', 'The Wood Duck looks painted by hand, but its beauty is matched by sharp flying through trees and watery forest. It even nests in holes high above the ground.'),
    ('en', 'wood-stork', 'The touch-hunting stork animal', 'The Wood Stork feeds by feel, sweeping its bill through water and snapping shut when something touches it. It proves you do not always need sharp eyes if your timing is sharp enough.'),
    ('en', 'yak', 'The cold-plateau engine animal', 'The Yak is a mountain powerhouse covered in a long shaggy coat that keeps out the cold. It can work, graze, and travel where the air is thin and the weather feels hard.'),
    ('en', 'zebra-shark', 'The spotted reef glider animal', 'The Zebra Shark moves slowly over sand and reef with a tail that seems made for smooth steering. Its calm style hides a body built for patient searching.'),
    ('en', 'african-forest-elephant', 'The quiet rainforest giant animal', 'The African Forest Elephant moves through thick rainforest like a living path-maker, opening space and spreading seeds as it goes. It is smaller than the savannah elephant, but in the forest it feels just as powerful.'),
    ('en', 'gerenuk', 'The standing branch-reacher animal', 'The Gerenuk eats leaves in a funny way by standing up on its back legs like a tiny deer ballerina. It turns extra height into extra dinner.'),
    ('en', 'impala', 'The spring-jumping grassland animal', 'The Impala can explode into huge leaps that seem to bounce right over danger. In a herd, quick eyes and quick legs keep the group moving like one wave.'),
    ('en', 'nyala', 'The striped thicket ghost animal', 'The Nyala walks softly through thick green cover with stripes that help its body melt into leaves and shadow. It feels like a forest secret with hooves.'),
    ('en', 'greater-kudu', 'The spiral-horn woodland animal', 'The Greater Kudu looks almost magical with giant twisted horns rising above its head. Even such a big antelope can vanish into brush when it stays calm and still.'),
    ('en', 'gemsbok', 'The desert spear antelope animal', 'The Gemsbok is a desert antelope that looks painted in black, white, and sand. It can travel through hot dry places with the stubborn calm of something built for heat.'),
    ('en', 'waterbuck', 'The riverbank watchful animal', 'The Waterbuck likes to stay close to water, where tall grass and reeds can help it hide or escape. It knows that a good home includes a good backup plan.'),
    ('en', 'springbok', 'The bouncing open-plain animal', 'The Springbok jumps so high and lightly that it can look like a toy on springs. In big open country, that bouncing energy says, ''I am ready if danger comes.'''),
    ('en', 'dik-dik', 'The tiny thorn-bush animal', 'The Dik-dik is a very small antelope with a little nose that helps cool the air it breathes. It survives by being quick, careful, and never too far from cover.'),
    ('en', 'zebra-duiker', 'The striped rainforest hoof animal', 'The Zebra Duiker is a shy forest antelope with stripes that look like little forest shadows painted across its back. It moves where the light is broken and the leaves stay thick.'),
    ('en', 'southern-pudu', 'The pocket-sized deer animal', 'The Southern Pudu is one of the smallest deer on Earth, like a forest fawn that never stopped being tiny. It hides in thick green places where being little is an advantage.'),
    ('en', 'reeves-muntjac', 'The barking little deer animal', 'Reeves''s Muntjac is a small deer that gives a loud bark when danger feels close. It is proof that a little body can still have a big warning voice.'),
    ('en', 'sika-deer', 'The spotted woodland deer animal', 'The Sika Deer carries white spots that can make it look dappled like sunlight on leaves. It belongs to the kind of places where forest and open ground meet.'),
    ('en', 'fallow-deer', 'The shovel-antler meadow animal', 'The Fallow Deer has antlers that look like broad little tree branches shaped into shovels. It moves through meadows and woods with a quiet, storybook kind of grace.'),
    ('en', 'chamois', 'The mountain goat-antelope animal', 'The Chamois runs over rocky mountainsides as if the slope were just another path. It turns steep ground into something almost playful.'),
    ('en', 'takin', 'The shaggy mountain tank animal', 'The Takin looks like a goat, a cow, and a cloud got mixed together on a mountain. Its thick coat and strong body help it push through cold misty slopes.'),
    ('en', 'nilgai', 'The blue-gray stride animal', 'The Nilgai is a big antelope with long legs and a cool blue-gray color on males. It crosses open land with the easy confidence of something built for distance.'),
    ('en', 'musk-deer', 'The fang-toothed deer animal', 'The Musk Deer looks like a little deer, but instead of antlers it has tiny fang-like teeth. It is a reminder that nature does not always solve the same problem the same way.'),
    ('en', 'bharal', 'The blue mountain climber animal', 'The Bharal, also called blue sheep, lives in high places where rock, wind, and sky all feel close together. It keeps its footing where many animals would slip.'),
    ('en', 'saola', 'The hidden mountain unicorn animal', 'The Saola is so rare and shy that people sometimes call it the Asian unicorn. It lives in wet mountain forest and feels like one of the world''s quietest mysteries.'),
    ('en', 'agouti', 'The seed-burying forest animal', 'The Agouti runs through the forest with quick legs and a nose for fallen treasure. By hiding seeds for later, it sometimes plants the next generation of trees.'),
    ('en', 'patagonian-mara', 'The rabbit-deer runner animal', 'The Patagonian Mara looks like a rabbit that borrowed the legs of a tiny deer. It belongs to wide dry places where speed and family teamwork matter.'),
    ('en', 'plains-vizcacha', 'The burrow-town hopper animal', 'The Plains Vizcacha lives in big underground neighborhoods with lots of tunnels and doorways. It shows how a small animal can become safer by building a whole village under the ground.'),
    ('en', 'crested-porcupine', 'The walking quill fortress animal', 'The Crested Porcupine carries long sharp quills that turn its back into a moving warning sign. It teaches that a strong shield can make a slow animal feel brave.'),
    ('en', 'white-faced-capuchin', 'The clever hand-using animal', 'The White-faced Capuchin uses smart hands and a busy mind to search, grab, and solve little problems in the trees. It lives like the forest is one big puzzle box.'),
    ('en', 'gelada', 'The grass-eating cliff monkey animal', 'The Gelada spends much of its life high in the mountains, sitting in big groups and plucking grass with careful fingers. It turns a windy plateau into a busy monkey city.'),
    ('en', 'golden-lion-tamarin', 'The golden mane tree animal', 'The Golden Lion Tamarin looks like a little sun with a tail, glowing orange in the green forest. Its tiny body depends on the trees staying connected and alive.'),
    ('en', 'emperor-tamarin', 'The mustached branch-runner animal', 'The Emperor Tamarin looks as if it put on a giant white mustache for fun. It darts through branches with its family like a tiny forest acrobat troop.'),
    ('en', 'bald-uakari', 'The red-faced river monkey animal', 'The Bald Uakari has a bright red face and a short tail that make it look unlike almost any other monkey. It belongs to forests that spend part of the year under water.'),
    ('en', 'woolly-monkey', 'The soft swinging canopy animal', 'The Woolly Monkey moves through the trees with a tail that can grab like another hand. It turns the high forest into a soft moving road.'),
    ('en', 'bonobo', 'The peace-making forest ape animal', 'The Bonobo is a great ape with a gentle face and a social style that often chooses peace over fights. It shows that strong communities can be built with calm, not just force.'),
    ('en', 'patas-monkey', 'The running savannah monkey animal', 'The Patas Monkey spends more time on the ground than many monkeys and can run very fast across open country. It feels like a tree animal that learned a grassland trick.'),
    ('en', 'drill', 'The deep-forest power monkey animal', 'The Drill is a strong forest monkey with a serious face and a body built for life in thick cover. It reminds us that many powerful animals are now rare because their forests are shrinking.'),
    ('en', 'pygmy-slow-loris', 'The sleepy moon-eyed animal', 'The Pygmy Slow Loris moves through branches so carefully that it can seem almost toy-like. Its slow pace is not laziness; it is part of the plan.'),
    ('en', 'pygmy-hippopotamus', 'The shy little hippo animal', 'The Pygmy Hippopotamus is like a hidden forest version of the big river hippo. It stays quiet and private in dark wet places where even large animals can disappear.'),
    ('en', 'bairds-tapir', 'The trunk-nosed forest animal', 'Baird''s Tapir looks like a forest pig with a tiny trunk, but it is really a giant seed-carrying gardener. As it walks, eats, and swims, it helps forests grow.'),
    ('en', 'mountain-tapir', 'The woolly cloud-forest animal', 'The Mountain Tapir lives in cold wet mountain forests where mist hangs in the trees. Its thick coat and gentle snout make it look like a soft mountain gardener.'),
    ('en', 'striped-polecat', 'The warning-striped spray animal', 'The Striped Polecat wears bold black-and-white colors so other animals think twice. It believes in giving a clear warning before anything gets too close.'),
    ('en', 'pine-marten', 'The forest ribbon hunter animal', 'The Pine Marten moves through branches and trunks like a piece of living brown silk. It is small enough to be quick and bold enough to explore almost anywhere in the forest.'),
    ('en', 'fisher', 'The dark forest stalker animal', 'The Fisher is a quick strong mammal that slips through dark forests with quiet confidence. It shows how a narrow body and sharp mind can handle many kinds of prey.'),
    ('en', 'sable', 'The velvet taiga hunter animal', 'The Sable is a soft dark hunter of the cold forest, moving through branches and snow with easy grace. It looks gentle until you remember how sharp and alert it is.'),
    ('en', 'stoat', 'The white-winter dart animal', 'The Stoat is small, fast, and brave enough to chase prey into tight holes and tunnels. In winter, its coat can turn white so the snow becomes part of the disguise.'),
    ('en', 'european-badger', 'The tunnel-building woodland animal', 'The European Badger digs deep homes underground and returns to them again and again like a careful builder. Its world is half forest and half secret city below.'),
    ('en', 'bush-dog', 'The little pack hunter animal', 'The Bush Dog looks like a small rounded dog, but it hunts with friends and moves through wet places with confidence. Teamwork makes its small size feel much bigger.'),
    ('en', 'dhole', 'The red pack runner animal', 'The Dhole is a wild dog that works as a team, using stamina and group timing to wear prey down. Its strength lives in the pack, not in one hero.'),
    ('en', 'raccoon-dog', 'The masked marsh wanderer animal', 'The Raccoon Dog looks like a raccoon and a fox had a woodland cousin together, but it is its own strange thing. It survives by being flexible and eating what the season offers.'),
    ('en', 'bat-eared-fox', 'The big-eared bug hunter animal', 'The Bat-eared Fox has giant ears that help it hear tiny insects moving in the ground. It proves that careful listening can feed a whole life.'),
    ('en', 'corsac-fox', 'The pale steppe fox animal', 'The Corsac Fox belongs to windy open grasslands where the land stretches far and shelter can be hard to find. Its pale coat and careful habits help it fit that wide world.'),
    ('en', 'gray-fox', 'The tree-climbing fox animal', 'The Gray Fox breaks the usual fox rule by climbing trees when it wants safety or fruit. It feels like a fox that borrowed a little cat magic.'),
    ('en', 'senegal-bushbaby', 'The moon-eyed leaper animal', 'The Senegal Bushbaby bounces through the dark with giant eyes and little hands ready for branches. It is tiny, but the night forest seems made to fit it.'),
    ('en', 'greater-glider', 'The floating tree-shadow animal', 'The Greater Glider does not flap like a bird; it opens its skin like a little living kite and sails from tree to tree. The forest becomes a sky-road when the branches are close enough.'),
    ('en', 'red-shanked-douc', 'The painted canopy monkey animal', 'The Red-shanked Douc looks so colorful that it seems dressed for a parade in the trees. But its bright beauty depends on real forests staying whole and quiet.'),
    ('en', 'tayra', 'The curious forest runner animal', 'The Tayra moves with the restless confidence of an animal that expects the world to have surprises. It climbs, runs, and searches as if every corner might hide something good.'),
    ('en', 'marabou-stork', 'The cleanup marsh giant animal', 'The Marabou Stork looks a little odd and a little serious, but it helps clean up what is left behind. It turns mess into an important job.'),
    ('en', 'jabiru', 'The giant marsh walker animal', 'The Jabiru is a huge stork that steps through wetlands as if the mud were a stage made for it. Its giant bill and giant legs help it hunt in shallow water with calm patience.'),
    ('en', 'golden-eagle', 'The golden mountain hunter animal', 'The Golden Eagle rides high air over mountains and open land, looking for the right moment to drop. From far above, the ground starts to look readable.'),
    ('en', 'wedge-tailed-eagle', 'The wedge-tailed sky ruler animal', 'The Wedge-tailed Eagle rides warm air over huge Australian spaces with wings built for staying aloft. It makes giant landscapes feel a little smaller.'),
    ('en', 'great-horned-owl', 'The horned night ruler animal', 'The Great Horned Owl looks fierce even when it is sitting still, with ear-like tufts and huge eyes. At night, it makes the dark feel full of quiet authority.'),
    ('en', 'eurasian-eagle-owl', 'The orange-eyed giant owl animal', 'The Eurasian Eagle-Owl is one of the biggest owls in the world, with glowing orange eyes and a heavy calm presence. It makes cliffs and forests feel watched.'),
    ('en', 'tawny-frogmouth', 'The broken-branch night animal', 'The Tawny Frogmouth can sit so still on a branch that it looks like part of the tree itself. It wins by pretending to be wood until the night meal arrives.'),
    ('en', 'kea', 'The mountain trickster parrot animal', 'The Kea is a smart parrot that lives in cold mountains instead of warm jungle. It pokes, tests, and investigates everything as if the whole world were a toy.'),
    ('en', 'red-legged-seriema', 'The long-legged caller animal', 'The Red-legged Seriema runs through grassland with long legs and a voice that carries far. It proves that a ground bird can still feel tall and dramatic.'),
    ('en', 'horned-screamer', 'The horned marsh caller animal', 'The Horned Screamer looks like a wetland bird wearing a strange little antenna on its head. Its loud voice helps turn wide marshes into a place full of signals.'),
    ('en', 'common-murre', 'The cliff-diving ocean bird animal', 'The Common Murre stands like a little bowling pin on crowded cliffs, then dives into cold water using its wings like underwater paddles. It belongs to two worlds at once.'),
    ('en', 'northern-fulmar', 'The wind-gliding seabird animal', 'The Northern Fulmar rides ocean wind for long distances with a calm stiff-winged style. It is a bird built to trust air and saltwater every day.'),
    ('en', 'magnificent-frigatebird', 'The pirate sky glider animal', 'The Magnificent Frigatebird spends so much time in the air that it can seem more like sky than bird. It steals, soars, and twists through wind with astonishing control.'),
    ('en', 'cattle-egret', 'The hoof-following white bird animal', 'The Cattle Egret likes to walk near big animals and catch the insects they stir up. It shows that smart timing can turn somebody else''s footsteps into your dinner bell.'),
    ('en', 'black-skimmer', 'The water-slicing flyer animal', 'The Black Skimmer flies just above the water with its lower bill cutting the surface like a tiny blade. It catches fish by turning flight itself into a tool.'),
    ('en', 'european-goldfinch', 'The thistle-seed song animal', 'The European Goldfinch is bright, nimble, and built for picking tiny seeds from spiky plants. It makes small overlooked food look valuable.'),
    ('en', 'scarlet-ibis', 'The red wetland flame animal', 'The Scarlet Ibis glows bright red in mudflats and mangroves like a flying piece of sunset. Its curved bill searches the soft ground for hidden food.'),
    ('en', 'boat-billed-heron', 'The scoop-billed night bird animal', 'The Boat-billed Heron has a bill so wide it looks like a little boat on its face. In the dark, that funny shape helps it fish in quiet wet places.'),
    ('en', 'burrowing-parrot', 'The cliff-tunnel parrot animal', 'The Burrowing Parrot digs nest tunnels into cliffs instead of nesting in tree holes. It turns stone walls into a noisy feather city.'),
    ('en', 'little-egret', 'The yellow-toed wader animal', 'The Little Egret steps lightly through shallow water with yellow feet that can stir up hidden prey. It shows how even a small color detail can become part of the hunt.'),
    ('en', 'black-footed-albatross', 'The endless Pacific sailor animal', 'The Black-footed Albatross spends so much time over the ocean that land feels like a rare visit. It is built for long wind roads above moving water.'),
    ('en', 'bee-hummingbird', 'The tiniest flower rocket animal', 'The Bee Hummingbird is so small it can feel like a spark with feathers. It hovers in front of flowers and drinks sweet fuel with perfect control.'),
    ('en', 'ruffed-grouse', 'The drumming forest bird animal', 'The Ruffed Grouse blends into leaves and bark until it suddenly beats the air with its wings like a tiny forest drum. It turns sound into a springtime signal.'),
    ('en', 'mata-mata', 'The leaf-monster turtle animal', 'The Mata Mata looks like a pile of wet leaves that somehow came alive and grew a snorkel nose. It wins by looking strange enough to disappear.'),
    ('en', 'gharial', 'The long-snout river reptile animal', 'The Gharial has a nose so long and narrow that it seems borrowed from a different creature. That shape helps it catch fish in big rivers, but it also means it needs a very specific home.'),
    ('en', 'eyelash-viper', 'The eyelash branch snake animal', 'The Eyelash Viper comes in many colors and waits quietly on branches for something to come close enough. It shows how stillness can be just as sharp as speed.'),
    ('en', 'madagascar-day-gecko', 'The bright sticky gecko animal', 'The Madagascar Day Gecko is a green little climber that shines in daylight instead of hiding from it. Its toes let it stick to smooth places as if gravity were only a suggestion.'),
    ('en', 'mexican-beaded-lizard', 'The beaded desert dragon animal', 'The Mexican Beaded Lizard moves slowly, but it carries real power inside a heavy beaded body. It is a creature that believes in patience more than hurry.'),
    ('en', 'armadillo-girdled-lizard', 'The dragon-roll armor animal', 'The Armadillo Girdled Lizard can grab its own tail and roll into a spiky ring when scared. It turns its whole body into a shield.'),
    ('en', 'eastern-indigo-snake', 'The midnight-blue serpent animal', 'The Eastern Indigo Snake is a long shining snake with a calm dark glow to its scales. It moves boldly through daylight like it knows exactly where it is going.'),
    ('en', 'mangrove-snake', 'The black-yellow branch snake animal', 'The Mangrove Snake wears bold stripes like a warning painted by the night. It glides through branches and wet forest edges with striking confidence.'),
    ('en', 'pancake-tortoise', 'The flat-shell rock animal', 'The Pancake Tortoise has a flatter shell than most tortoises, which helps it slip into cracks between rocks. It survives by being flatter and faster than you might expect from a tortoise.'),
    ('en', 'purple-frog', 'The underground purple frog animal', 'The Purple Frog spends most of its life hidden under the ground and comes up for only a short time when the rains arrive. It is like a secret the monsoon tells once a year.'),
    ('en', 'cayenne-caecilian', 'The secret noodle amphibian animal', 'The Cayenne Caecilian looks a little like an eel and a worm had an underwater cousin. It lives where mud and water meet, in a world most people never notice.'),
    ('en', 'giant-waxy-monkey-frog', 'The slow waxy tree frog animal', 'The Giant Waxy Monkey Frog walks along branches instead of hopping wildly and spreads a special wax over its skin to keep moisture in. It is calm because it understands its own needs.'),
    ('en', 'tiger-shark', 'The striped sea hunter animal', 'The Tiger Shark moves through warm water with a wide head and stripes that fade as it grows. It is a strong ocean hunter built to notice many kinds of chances.'),
    ('en', 'bull-shark', 'The river-entering shark animal', 'The Bull Shark can move from the sea into rivers, which gives it access to places many sharks never go. It wins by being built for more than one kind of water.'),
    ('en', 'oceanic-whitetip-shark', 'The white-finned bluewater animal', 'The Oceanic Whitetip Shark belongs to the huge empty-looking blue water far from land. Its long white-tipped fins help it travel through a place where food can be scattered and hard to find.'),
    ('en', 'smalltooth-sawfish', 'The saw-nosed sea animal', 'The Smalltooth Sawfish carries a long flat snout lined with teeth like a living saw. It is amazing and ancient-looking, but today it is also one of the most fragile fish in the sea.'),
    ('en', 'weedy-seadragon', 'The drifting seaweed dragon animal', 'The Weedy Seadragon looks like seaweed that decided to drift on purpose. Its body turns camouflage into art.'),
    ('en', 'mudskipper', 'The walking fish animal', 'The Mudskipper acts like a fish that forgot it was supposed to stay underwater. It hops on mud, peers around with popping eyes, and lives right on the line between sea and land.'),
    ('en', 'archerfish', 'The water-spitting fish animal', 'The Archerfish knocks insects off branches by shooting little jets of water with surprising aim. It proves that a fish can solve sky problems from below.'),
    ('en', 'humpback-anglerfish', 'The glowing deep hunter animal', 'The Humpback Anglerfish lives in black deep water and dangles a little light like a baited lantern. Down there, tricking dinner into coming close is smarter than chasing.'),
    ('en', 'barreleye', 'The clear-headed deep animal', 'The Barreleye looks almost made of glass, with eyes that can point upward inside its clear head. It is one of those deep-sea animals that makes the ocean feel like another planet.'),
    ('en', 'giant-isopod', 'The armored sea roly-poly animal', 'The Giant Isopod looks like a giant ocean version of a pill bug from the garden. It shows how old familiar shapes can return in huge strange forms down in the deep.'),
    ('en', 'luna-moth', 'The moon-green wing animal', 'The Luna Moth looks like a leaf made of moonlight, with long soft tails trailing behind it. Its adult life is brief and beautiful, like a message carried on wings.'),
    ('en', 'goliath-birdeater', 'The giant jungle spider animal', 'The Goliath Birdeater is one of the biggest spiders in the world, with enough size to make the forest floor feel dramatic. Yet it still survives by shelter, warning, and timing.')
